import{_ as a,o as i,c as r,ag as t}from"./chunks/framework.DXGyWiRo.js";const n="/images/uebung010.jpg",p="/images/uebung009.jpg",c=JSON.parse('{"title":"Übung Lektion 5","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung05.md","filePath":"lektionen/uebung05.md"}'),s={name:"lektionen/uebung05.md"};function d(o,e,u,m,l,h){return i(),r("div",null,[...e[0]||(e[0]=[t('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-5" tabindex="-1">Übung Lektion 5 <a class="header-anchor" href="#ubung-lektion-5" aria-label="Permalink to &quot;Übung Lektion 5&quot;">​</a></h1><p>A) Übersetzen Sie folgende Sätze und Komposita und lösen Sie die darin vorkommenden Dvandvas in Sanskrit auf:</p><p>1. catvāro varṇā brāhmaṇakṣatriyavaiśyaśūdrāḥ. (Āpastambīyadharmasūtra I,1,1,4 = Vāsiṣṭhadharmaśāstra II,1)</p><p>चत्वारो वर्णा ब्राह्मणक्षत्रियवैश्यशूद्राः ||</p><p>Erklärung catvāras = चत्वारस् = &quot;vier&quot;</p><p>Brahmanen, Kṣatriyas, Vaiśyas und Śūdras sind die vier Stände.</p><p>catvāro varnā brāhmaṇaḥ kṣatriyo vaiśyaḥ śūdraś ca / catvāro varṇā brāhmaṇāḥ kṣatriyā vaiśyāḥ śūdrāś ca.</p><p>चत्वारो वर्णा ब्राह्मणः क्षत्रियो वश्यः शूद्रश्च । चत्वारो वर्णब्राह्मणाः क्षत्रिया वश्याः शूद्राश्च ।</p><p>2. trayo varṇā dvijātayo brāhmaṇakṣatriyavaiśyāḥ. (Vāsiṣṭhadharmaśāstra II,1)</p><p>त्रयो वर्णा द्विजातयो ब्राह्मणक्षत्रियवैश्याः ||</p><p>Erklärung: trayas = त्रयस् =  &quot;drei&quot;</p><p>Brahmanen, Kṣatriyas, und Vaiśyas sind die drei zweimalgeborenen Stände.</p><p>trayo varṇā dvijātayo brāhmaṇaḥ kṣatriyo vaiśyaś ca / trayo varṇā dvijātayo brāhmaṇāḥ kṣatriyā vaiśyāś ca.</p><p>त्रयो वर्णा द्विजातयो ब्राह्मणः क्षत्रियो वैश्यश्च । त्रयो वर्णाद्विजातयो ब्राह्मणाः क्षत्रिया वैश्याश्च ।</p><p>3. sāmavedargvedayajurvedās trayī. (Kauṭilīya-arthaśāstra 1.3.1.) (in gutem Sanskrit: sāmargyajurvedās trayī)</p><p>सामवेदर्ग्वेदयजुर्वेदास्त्रयी ||</p><p>(in gutem Sanskrit: सामर्ग्यजुर्वेदास्त्रयी)</p><p>Die drei Veden sind: Sāmavaeda, Ṛgveda und Yajurveda.</p><p>sāmaveda ṛgvedo yajurvedaś ca trayī.</p><p>सामवेद ऋग्वेदो यजुर्वेदश्च त्रयी ।</p><p>4. Die drei Feinde des Menschen, die das Tor zur Hölle bilden (Viṣṇusmṛti 33,1+6): kāmakrodhalobhāḥ</p><p>कामक्रोधलोभाः ||</p><p>Leidenschaft, Zorn und Gier.</p><p>kāmaḥ krodho lobhaś ca.</p><p>कामः क्रोधो लोभश्च ।</p><p>5. maitrīkaruṇāmuditopekṣāś catvāro brahmavihārāḥ.</p><p>मैत्रीकरुणामुदितोपेक्षाश्चत्वारो ब्रह्मविहाराः ||</p><p>Erklärung: brahmavihāra: &quot;Verweilungszustände Brahmas&quot;, auch &quot;Unermessliche&quot; genannt: unbegrenzte Haltungen. Sie stellen buddhistische Meditationsformen dar, mit denen der Meditierende allmählich, schrittweise die ganze Wirklichkeit &quot;durchstrahlt&quot;. Auch im Yoga (Yogasūtra 1,33) spielen diese vier eine Rolle beim Zurruhekommen des Bewusstseins.</p><p>Die grenzenlosen Haltungen sind: Wohlwollen, Mitgefühl, Mitfreude und Gleichmut.</p><p>maitrī karuṇā muditopekṣā ca catvāro brahmavihārāḥ.</p><p>मैत्री करुणा मुदितोपेक्षा च चत्वारो ब्रह्मविहाराः ।</p><p>6. avidyāsmitārāgadveṣābhiniveṣāḥ pañca kleśāḥ. (Yogasūtra 2,3)</p><p>अविद्यास्मितारागद्वेषाभिनिवेषाः पञ्च क्लेशाः ||</p><p>Erklärung: pañca = &quot;fünf&quot;</p><p>Die fünf Plagen sind: Unwissenheit, Ichsucht, Gier, Hass und Körperbezogenheit.</p><p>avidyāsmitā rāgo dveṣo &#39;bhiniveṣaś ca pañca kleśāḥ.</p><p>अविद्यास्मिता रागो द्वेषो ऽभिनिवेषश्च पञ्च क्लेशाः ।</p><p>7. ānvīkṣikītrayīvārttādaṇḍanitayo vidyāḥ. (Nach Kauṭilīya-arthaśāstra 1.2.1.)</p><p>आन्वीक्षिकीत्रयीवार्त्तादण्डनितयो विद्याः ||</p><p>Wissenschaften sind Philosophie, Vedistik, Ökonomie und Politik.</p><p>ānvīkṣikī trayī vārttā daṇḍanītiś ca vidyāḥ.</p><p>आन्वीक्षिकी त्रयी वार्त्ता दण्डनीतिश्च विद्याः ।</p><p><img src="'+n+'" alt=""><br> Abb.: abhiniveśo na vā ? = अभ्निवेशो न वा । Körperbezogenheit oder nicht ? -- das ist hier dies Frage<br> &quot;Schöne mit dem Spiegel&quot;, Belur (ಬೇಲೂರು), Karnataka (ಕರ್ನಾಟಕ)<br> [Bildquelle: ~Panache. -- <a href="http://www.flickr.com/photos/enamor/278398152/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/enamor/278398152/</a>. -- Zugriff am 2008-11-28. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung)]</p><p>A) Übersetzen Sie:</p><p>1. vidyā vārttā.</p><p>विद्या वार्त्ता |</p><p>Ökonomie ist eine Wissenschaft.</p><p>2. brāhmaṇaḥ kṣatriyo vaiśyaś ca trayo varṇā dvijātayaḥ.</p><p>ब्राह्मणः क्षत्रियो वैश्यश्च त्रयो वर्णा द्विजातयः |</p><p>Die drei zweimalgeborenen Stände sind: Brahmane, Kṣatriya und Vaiśya.</p><p>3. dvijā vaiśyāḥ. (2 Möglichkeiten)</p><p>द्विजा वैश्याः |</p><p>Vaiśyas sind Zweimalgeborene / Vaiśyafrauen sind Zweimalgeborene.</p><p>B) Setzen Sie die entsprechende Form ein:</p><p>(dvija, sādhu, kavi) ... rāmaḥ</p><p>(द्विज, साधु, कवि) ... रामः |</p><p>dvijo rāmaḥ. sādhū rāmaḥ. kavī rāmaḥ.</p><p>द्विजो रामः । साधू रामः । कवी रामः ।</p><p>(devī) ... indrāṇī</p><p>(देवी) ... इन्द्राणी |</p><p>devīndrāṇī.</p><p>देवीन्द्राणी ।</p><p>dvijātayas ... (vaiśyā, kṣatriya)</p><p>द्विजातयस् ... (वैश्या, क्षत्रिय) |</p><p>dvijātayo vaiśyāḥ. dvijātayaḥ kṣatriyāḥ.</p><p>द्विजातयो वश्याः । द्विजातयः क्षत्रियाः ॥</p><p>C) Lösen Sie das Kompositum in folgendem Satz in Sanskrit auf und bilden Sie mit dieser aufgelösten Form denselben Satz:</p><p>sāmargyajurvedās trayī.</p><p>सामर्ग्यजुर्वेदास्त्रयी |</p><p>sāmaveda ṛgvedo yajurvedaś ca trayī / ... yajurvedas trayī</p><p>सामवेद ऋग्वेदो यजुर्वेदश्च त्रयी । ... यजुर्वेदस्त्रयी ॥</p><p>D) Übersetzen Sie auf zwei Weisen ins Sanskrit (einmal  mit einem Kompositum, einmal ohne):</p><p>&quot;Verweilungszustände Brahmas&quot; sind: freundliches Wohlwollen, Mitgefühl, Mitfreude, Gleichmut.</p><p>maitrīkaruṇāmuditopekṣā brahmavihārāḥ. maitrī karunā muditopekṣā (ca) brahmavihārāḥ.</p><p>मैत्रीकरुणामुदितोपेक्षा ब्रह्मविहाराः । मैत्री करुणा मुदितोपेक्षा (च) ब्रह्मविहाराः ॥</p><p><img src="'+p+'" alt=""><br> Abb.: ṛgvedaḥ = ऋग्वेदः<br> Ṛgveda-Manuskript, frühes 19. Jhdt. n. Chr.<br> [Bildquelle: Wikipedia. Public domain]</p>',77)])])}const g=a(s,[["render",d]]);export{c as __pageData,g as default};
